--- 获取攻击目标
---@param targetIds CombatEntity
---@return table
function M:GetAttackTargets(targetIds)
	local ret = {}
	for _, targetId in pairs(targetIds) do
		local target = self:GetEntityById(targetId)
		if target then
			table.insert(ret, target)
		end
	end
	return ret
end

