--- 添加技能到实体
---@param entityId number 实体ID
---@param skillData table 技能数据
function M:AddSkillToEntity(entityId, skillData)
	local entity = self:GetEntityById(entityId)
	if entity then
		local skill = Skill:New(skillData)
		entity:AddSkill(skillData.id, skill)
		print("[CombatManager] Added skill", skillData.id, "to entity", entityId)
	else
		print("[CombatManager] Failed to add skill - entity not found:", entityId)
	end
end

--- 添加Buff到实体
---@param entityId number 实体ID
---@param buffData table Buff数据
function M:AddBuffToEntity(entityId, buffData)
	local entity = self:GetEntityById(entityId)
	if entity then
		local buff = Buff:New(buffData)
		entity:AddBuff(buffData.id, buff)

		--- 记录Buff行动到战斗日志
		self.battleLog:LogBuffAction(entityId, buffData.id, buffData.effectType or "none", buffData.effectValue or 0)

		print("[CombatManager] Added buff", buffData.id, "to entity", entityId)
	else
		print("[CombatManager] Failed to add buff - entity not found:", entityId)
	end
end

--- 根据ID获取实体
---@param entityId number 实体ID
---@return CombatEntity|nil
function M:GetEntityById(entityId)
	if not self.roundManager then
		return nil
	end

	local allEntities = self.roundManager:GetAllEntities()
	for _, entity in ipairs(allEntities) do
		if entity.id == entityId then
			return entity
		end
	end
	return nil
end

--- 获取实体的技能
---@param entityId number 实体ID
---@param skillId number 技能ID
---@return Skill|nil
function M:GetEntitySkill(entityId, skillId)
	local entity = self:GetEntityById(entityId)
	if entity then
		return entity:GetSkill(skillId)
	end
	return nil
end

--- 获取实体的所有技能
---@param entityId number 实体ID
---@return table
function M:GetEntityAllSkills(entityId)
	local entity = self:GetEntityById(entityId)
	if entity then
		return entity:GetAllSkills()
	end
	return {}
end

--- 获取实体的Buff
---@param entityId number 实体ID
---@param buffId number BuffID
---@return Buff|nil
function M:GetEntityBuff(entityId, buffId)
	local entity = self:GetEntityById(entityId)
	if entity and entity.buffs then
		return entity.buffs[buffId]
	end
	return nil
end

--- 移除实体的Buff
---@param entityId number 实体ID
---@param buffId number BuffID
function M:RemoveEntityBuff(entityId, buffId)
	local entity = self:GetEntityById(entityId)
	if entity then
		entity:RemoveBuff(buffId)
		print("[CombatManager] Removed buff", buffId, "from entity", entityId)
	end
end

